function applyPhotoDataToConfig() {
  if (typeof INCENTIVE_CONFIG === 'undefined' || !PHOTO_DATA) return;
  var PHOTO_EMPLOYEE_ALIASES = {
    '鍐潠銆佽４淇婃櫤銆侀珮蹇楀湥銆佷警搴嗗悍': '鏁版嵁瀹夊叏鍥㈤槦'
  };
  function applyPhoto(emp) {
    if (!emp) return;
    if (emp.members && emp.members.length) {
      emp.members.forEach(function (m) {
        if (m.name && PHOTO_DATA[m.name]) m.photo = PHOTO_DATA[m.name];
      });
      return;
    }
    var photoKey = PHOTO_EMPLOYEE_ALIASES[emp.name] || emp.name;
    if (photoKey && PHOTO_DATA[photoKey]) emp.photo = PHOTO_DATA[photoKey];
  }
  [INCENTIVE_CONFIG.management, INCENTIVE_CONFIG.sales].forEach(function (dept) {
    (dept.months || []).forEach(function (month) {
      (month.employees || []).forEach(applyPhoto);
    });
  });
}
applyPhotoDataToConfig();
